INSERT INTO public.messages_logs (id, protocol, contact, agent_id, agent_name, message_content, timestamp, has_empathy, closing_attempt, final_score, created_at, empathy_score, clarity_score, depth_score, commercial_score, agility_score, message_count, upload_id, status, is_commercial, overall_conclusion, improvements) VALUES ($tag$f0854876-e22f-4054-90a1-c226fd7ad1f6$tag$, $tag$2026010900003$tag$, $tag$Thiago do Amaral (5583981653638)$tag$, NULL, $tag$Thayanne Sales$tag$, $tag$[{"role":"client","text":"Oi, já preenchi meus dados na página Teologia EAD e quero mais informações.","time":"09/01/2026 05:45:25"},{"role":"client","text":"Por favor aguarde, em breve uma das nossas Consultoras lhe passará todas as informações.","time":"09/01/2026 05:45:26"},{"role":"client","text":"Aguarde só um momento!\n\nNeste instante, todos os nossos consultores estão prestando atendimento, o que pode gerar uma pequena espera.\n\nEstamos dedicando total atenção aos clientes que estão à sua frente. Assim que o próximo atendente estiver livre, ele irá assumir o seu chamado imediatamente.\n\nPedimos a sua compreensão e agradecemos por aguardar!","time":"09/01/2026 05:45:27"},{"role":"client","text":"Gostaria de Saber o curso de Teologia Presencial","time":"09/01/2026 06:31:24"},{"role":"client","text":"Seja bem-vindo à Cidade Viva. Sou Thayanne Sales","time":"09/01/2026 08:09:12"},{"role":"agent","text":"*Thayanne Sales:* Vou lhe enviar as informações sobre o curso","time":"09/01/2026 08:09:25","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Thayanne Sales:*  A nossa *Graduação em Teologia Presencial* é Bacharelado e reconhecida pelo MEC ( *bit.ly/3LlEgJS* ), com a duração de 3 anos.\n\nNo formato presencial as aulas acontecem de segunda à quinta-feira das 19h00 às 22h00 aqui no Polo João Pessoa, localizado na Rua Luzia Simões Bartoline, 50 - Aeroclube, João Pessoa-PB.\n\nA nossa base filosófica e teológica é fundamentada na cosmovisão cristã, utilizando o método histórico-gramatical para a interpretação das Sagradas Escrituras. Como Faculdade, diferenciamo-nos de um seminário, que geralmente segue um viés denominacional. Contamos com professores de diferentes tradições cristãs, como Presbiteriana, Batista, Adventista e Anglicana, valorizando assim a integridade intelectual. Todos os nossos docentes são especializados nas suas áreas de atuação.","time":"09/01/2026 08:09:33","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Thayanne Sales:*  Segue a matriz curricular do curso de Teologia *bit.ly/3xljQgl*","time":"09/01/2026 08:09:37","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Thayanne Sales:* A mensalidade da Graduação Presencial em Teologia fica R$ 549,56.\n\n🤩 Estamos com uma condição especial, *desconto de 30%* na pontualidade durante toda graduação, que fica apenas R$ 384,69.  *Usando o cupom de desconto: BOLSA30*\n\nNão há taxa de matrícula, sendo a primeira mensalidade paga no ato da matrícula, e as demais mensalidades pagas no dia 10 dos meses subsequentes ao início das aulas.\n\n🌟 *Valor promocional:* (Semestralidade R$ 2.308,15).\n\n⚠ *Valor mensal está sujeito a mudança de acordo a data de matrícula:*\n \nMatrículas realizadas até em JANEIRO: 6 mensalidades de R$ 384,69 = R$ 2.308,15\nMatrículas realizadas até em FEVEREIRO: 5 mensalidades de R$ 461,63 = R$ 2.308,15\nMatrículas realizadas até MARÇO: 04 mensalidades R$ 577,03 = R$ 2.308,15\n\n🗓️ Início das aulas: Fevereiro de 2026 📚💻","time":"09/01/2026 08:09:44","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Thayanne Sales:* ✅ PROCEDIMENTO DE MATRÍCULA:\n\nRealize a matrícula de acordo com a sua forma de ingresso, basta acessar o link correspondente abaixo:\n\n1 - Aproveitamento do ENEM:\nbit.ly/FICV-Enem\n\n2 - Vestibular Agendado:\nbit.ly/FICV-Vestibular\n\n3 - Seleção de Graduados:\nbit.ly/FICV-Graduados\n\n📝 Após preencher seus dados, o sistema disponibilizará o pagamento da primeira parcela e o contrato para aceite. Não há cobrança de matrícula.😊","time":"09/01/2026 08:09:50","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"client","text":"Ot","time":"09/01/2026 08:24:06"},{"role":"client","text":"Ótimo","time":"09/01/2026 08:24:11"},{"role":"client","text":"Quais os dias de aulas ?","time":"09/01/2026 08:24:19"},{"role":"agent","text":"*Thayanne Sales:* No formato presencial as aulas acontecem de segunda à quinta-feira das 19h00 às 22h00 aqui no Polo João Pessoa, localizado na Rua Luzia Simões Bartoline, 50 - Aeroclube, João Pessoa-PB.","time":"09/01/2026 08:24:58","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"client","text":"Ótimo. Obrigado","time":"09/01/2026 11:13:39"},{"role":"client","text":"Atendimento Finalizado!\n\nThiago do Amaral, esperamos que sua solicitação tenha sido totalmente resolvida.\n\nO seu feedback é muito importante para nós, então agradecemos se puder avaliar nosso atendimento em uma pesquisa futura.\n\nA FICV agradece o seu contato. Estamos sempre à disposição!","time":"12/01/2026 08:09:16"},{"role":"client","text":"Sua sessão irá expirar em 2 minutos!","time":"12/01/2026 11:11:41"},{"role":"client","text":"Sua sessão expirou!","time":"12/01/2026 11:13:53"}]$tag$, $tag$2026-01-09 05:45:25+00$tag$, FALSE, FALSE, 6.6, $tag$2026-03-01 16:46:57.607947+00$tag$, 7, 10, 5, 2, 9, 6, $tag$65b591e2-df83-4fd5-9de1-52b0445d3ed1$tag$, $tag$approved$tag$, TRUE, NULL, '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET protocol = EXCLUDED.protocol, contact = EXCLUDED.contact, agent_id = EXCLUDED.agent_id, agent_name = EXCLUDED.agent_name, message_content = EXCLUDED.message_content, timestamp = EXCLUDED.timestamp, has_empathy = EXCLUDED.has_empathy, closing_attempt = EXCLUDED.closing_attempt, final_score = EXCLUDED.final_score, created_at = EXCLUDED.created_at, empathy_score = EXCLUDED.empathy_score, clarity_score = EXCLUDED.clarity_score, depth_score = EXCLUDED.depth_score, commercial_score = EXCLUDED.commercial_score, agility_score = EXCLUDED.agility_score, message_count = EXCLUDED.message_count, upload_id = EXCLUDED.upload_id, status = EXCLUDED.status, is_commercial = EXCLUDED.is_commercial, overall_conclusion = EXCLUDED.overall_conclusion, improvements = EXCLUDED.improvements;
INSERT INTO public.messages_logs (id, protocol, contact, agent_id, agent_name, message_content, timestamp, has_empathy, closing_attempt, final_score, created_at, empathy_score, clarity_score, depth_score, commercial_score, agility_score, message_count, upload_id, status, is_commercial, overall_conclusion, improvements) VALUES ($tag$39e08039-1126-4886-bc3c-48c95dbfbb0c$tag$, $tag$2026010900112$tag$, $tag$Naor (5583998798474)$tag$, NULL, $tag$Karina Pimentel$tag$, $tag$[{"role":"client","text":"oi","time":"09/01/2026 15:01:49"},{"role":"client","text":"🌟 Boa tarde Naor! Que alegria ter você aqui com a gente! 🙌","time":"09/01/2026 15:01:50"},{"role":"client","text":"Seja bem-vindo ao atendimento digital da Cidade Viva","time":"09/01/2026 15:01:54"},{"role":"client","text":"Você poderá tirar dúvidas sobre Igreja, Faculdade, Fundação, Livraria e nosso Sistema de Ensino.\n","time":"09/01/2026 15:01:58"},{"role":"client","text":"Agora, selecione no menu abaixo com qual área da Cidade Viva você deseja falar.","time":"09/01/2026 15:02:06"},{"role":"client","text":"Faculdade \n Faculdade Internacional Cidade Viva","time":"09/01/2026 15:02:16"},{"role":"client","text":"Olá! Naor!👋\n É um prazer te receber aqui, na Faculdade Internacional Cidade Viva. 😊","time":"09/01/2026 15:02:17"},{"role":"client","text":"Escolha uma opção abaixo para continuarmos:","time":"09/01/2026 15:02:21"},{"role":"client","text":"Falar com um atendente","time":"09/01/2026 15:02:36"},{"role":"client","text":"Certo! 🙌\n\nEstamos localizando um atendente para falar com você.\n\nEnquanto isso, me diz rapidinho:\n💬 Sobre qual assunto você precisa de ajuda?\n","time":"09/01/2026 15:02:38"},{"role":"client","text":"mensalidade","time":"09/01/2026 15:05:11"},{"role":"client","text":"Seja bem-vindo à Cidade Viva. Sou Karina Pimentel","time":"09/01/2026 15:08:22"},{"role":"client","text":"Oi Karina, boa tarde","time":"09/01/2026 15:08:40"},{"role":"agent","text":"*Karina Pimentel:* Como podemos lhe ajudar?","time":"09/01/2026 15:08:44","feedback":"⚠️ Pergunta Genérica: Evite perguntas que podem ser respondidas com \"não\". Tente: \"Qual sua maior motivação para estudar hoje?\""},{"role":"agent","text":"*Karina Pimentel:* Boa tarde!","time":"09/01/2026 15:08:53","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"client","text":"Gostaria de tirar uma dúvida quanto ao valor da mensalidade","time":"09/01/2026 15:08:59"},{"role":"agent","text":"*Karina Pimentel:* Já é aluno?","time":"09/01/2026 15:09:22","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"client","text":"O valor da mensalidade aumentou, ou ficou mais caro por ser rematricula?","time":"09/01/2026 15:09:34"},{"role":"client","text":"sou sim","time":"09/01/2026 15:09:37"},{"role":"agent","text":"*Karina Pimentel:* Teria o reajuste anual.","time":"09/01/2026 15:10:55","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Karina Pimentel:* Teologia seria o curso?","time":"09/01/2026 15:11:09","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"client","text":"sim","time":"09/01/2026 15:19:04"},{"role":"agent","text":"*Karina Pimentel:* Foi reajuste de 6%","time":"09/01/2026 15:19:30","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"client","text":"Mas, esse foi o caso do aumento?","time":"09/01/2026 15:19:33"},{"role":"client","text":"ahhh","time":"09/01/2026 15:19:42"},{"role":"client","text":"era isso que eu queria saber","time":"09/01/2026 15:19:44"},{"role":"client","text":"porque quem paga o meu curso é a a igreja que eu congrego","time":"09/01/2026 15:20:01"},{"role":"client","text":"preciso explicar o motivo do aumento na mensalidade","time":"09/01/2026 15:21:28"},{"role":"client","text":"Karina, muito obrigado","time":"09/01/2026 15:21:40"},{"role":"client","text":"Deus abençoe!","time":"09/01/2026 15:21:42"},{"role":"client","text":"Já é dia 09, mas, te desejo um feliz 2026","time":"09/01/2026 15:21:53"},{"role":"agent","text":"*Karina Pimentel:* De nada!","time":"09/01/2026 15:29:56","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Karina Pimentel:* Qualquer duvida estamos a disposição!","time":"09/01/2026 15:30:15","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Karina Pimentel:* Amém, o senhor também!","time":"09/01/2026 15:30:35","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Karina Pimentel:* Feliz 2026!","time":"09/01/2026 15:30:45","feedback":"🚩 Fechamento Ausente: O contato está terminando. Sempre faça um convite para o próximo passo."},{"role":"client","text":"Atendimento Finalizado!\n\nNaor, esperamos que sua solicitação tenha sido totalmente resolvida.\n\nO seu feedback é muito importante para nós, então agradecemos se puder avaliar nosso atendimento em uma pesquisa futura.\n\nA FICV agradece o seu contato. Estamos sempre à disposição!","time":"09/01/2026 16:19:08"},{"role":"client","text":"Sua opinião é muito importante para nós.\nPor gentileza, avalie o atendimento realizado, considerando 1 como muito insatisfeito e 5 como muito satisfeito.","time":"09/01/2026 16:19:09"},{"role":"client","text":"Naor, Obrigado pelo seu interesse na Cidade Viva.\n\nCaso deseje outra informação, não hesite em entrar em contato com a gente!\n  \nAté mais!","time":"09/01/2026 16:34:10"}]$tag$, $tag$2026-01-09 15:01:49+00$tag$, FALSE, FALSE, 8.2, $tag$2026-03-01 16:46:57.607947+00$tag$, 10, 10, 10, 2, 9, 10, $tag$65b591e2-df83-4fd5-9de1-52b0445d3ed1$tag$, $tag$approved$tag$, TRUE, NULL, '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET protocol = EXCLUDED.protocol, contact = EXCLUDED.contact, ag