ssim que o próximo atendente estiver livre, ele irá assumir o seu chamado imediatamente.\n\nPedimos a sua compreensão e agradecemos por aguardar!","time":"09/01/2026 06:44:51"},{"role":"client","text":"Ok. É só pra dizer que não consigo finalizar minha inscrição no vosso portal","time":"09/01/2026 06:45:40"},{"role":"client","text":"Arquivo de imagem | (https://igrejabatista.widechat.com.br/config/storage/view/6960ce6f6948ef178e02fdf1)","time":"09/01/2026 06:46:23"},{"role":"client","text":"Não consigo visualizar comprovante nem contrato","time":"09/01/2026 06:46:56"},{"role":"client","text":"Ou talvez sou que não entendi com funciona","time":"09/01/2026 06:47:16"},{"role":"client","text":"Não consigo fazer o pagamento da matrícula","time":"09/01/2026 06:50:15"},{"role":"client","text":"Seja bem-vindo à Cidade Viva. Sou Thayanne Sales","time":"09/01/2026 08:06:35"},{"role":"agent","text":"Arquivo de áudio | (https://igrejabatista.widechat.com.br/config/storage/view/6960e15aa5323ed12205a754)","time":"09/01/2026 08:07:06","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"client","text":"Sua sessão irá expirar em 2 minutos!","time":"12/01/2026 06:48:16"},{"role":"client","text":"Sua sessão expirou!","time":"12/01/2026 06:50:18"}]$tag$, $tag$2026-01-09 06:43:54+00$tag$, FALSE, FALSE, 7, $tag$2026-03-01 16:46:57.607947+00$tag$, 9, 10, 5, 2, 9, 1, $tag$65b591e2-df83-4fd5-9de1-52b0445d3ed1$tag$, $tag$approved$tag$, TRUE, NULL, '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET protocol = EXCLUDED.protocol, contact = EXCLUDED.contact, agent_id = EXCLUDED.agent_id, agent_name = EXCLUDED.agent_name, message_content = EXCLUDED.message_content, timestamp = EXCLUDED.timestamp, has_empathy = EXCLUDED.has_empathy, closing_attempt = EXCLUDED.closing_attempt, final_score = EXCLUDED.final_score, created_at = EXCLUDED.created_at, empathy_score = EXCLUDED.empathy_score, clarity_score = EXCL