INSERT INTO public.messages_logs (id, protocol, contact, agent_id, agent_name, message_content, timestamp, has_empathy, closing_attempt, final_score, created_at, empathy_score, clarity_score, depth_score, commercial_score, agility_score, message_count, upload_id, status, is_commercial, overall_conclusion, improvements) VALUES ($tag$8c724056-d6f6-46dc-881c-5d9698681642$tag$, $tag$2026011300018$tag$, $tag$ðŸ§ðŸ½â€â™‚ï¸ (5583987633353)$tag$, NULL, $tag$Karina Pimentel$tag$, $tag$[{"role":"client","text":"Oi, já preenchi meus dados na página Direito e quero mais informações.","time":"13/01/2026 09:06:08"},{"role":"client","text":"Por favor aguarde, em breve uma das nossas Consultoras lhe passará todas as informações.","time":"13/01/2026 09:06:09"},{"role":"client","text":"Seja bem-vindo à Cidade Viva. Sou Karina Pimentel","time":"13/01/2026 09:09:35"},{"role":"agent","text":"*Karina Pimentel:* *Bacharelado em Direito*\n\n*GRADUAÇÃO COM COSMOVISÃO CRISTÃ*\nValorização do Direito clássico, sem viés ideológico, o Direito tratado numa cosmovisão cristã.\n\n*NOTA MÁXIMA NO MEC*\nGraduação com a maior avaliação junto ao MEC, conceito 05 estrelas ( *bit.ly/3LlEgJS* ) com duração de 5 anos. \n\n*PRÁTICA JURÍDICA*\nÚnico curso no Brasil com vivência de prática jurídica do primeiro ao décimo período.\n\n*NÚCLEO*\nPrimeiro e único núcleo de prática jurídica em Lei Geral de Proteção de Dados (LGPD).\n\n*VOCAÇÃO*\nEspecialização durante a graduação com disciplinas optativas nas áreas: \n\na) Serviço Público; \nb) Advocacia Empreendedora; \nc) Academia\n\n*BIBLIOTECA DIGITAL*\nRevista dos Tribunais online e a Biblioteca Digital Proview da Revista dos Tribunais. Kindles com assinatura Unlimited.\n\n*AULAS PRESENCIAIS*\nDe segunda à sexta, das 19h às 22h - goo.gl/maps/tb5occMvgJGHsjwz9.","time":"13/01/2026 09:10:01","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Karina Pimentel:* A mensalidade da Graduação em Direito está R$ 1.407,95. \n\n🤩 Estamos com uma condição excepcional, desconto de 60% na pontualidade durante toda graduação que ficará o valor de R$ 563,18.\n\nNão há taxa de matrícula, sendo a primeira mensalidade paga no ato da inscrição, e as demais mensalidades pagas até o dia 10 de cada mês.\n\n🌟 Valor promocional: (Semestralidade R$ 3.379,08).\n⚠️ Valor mensal está sujeito a mudança de acordo a data de matrícula:\n\n Matrículas realizadas até em JANEIRO: 6 mensalidades de R$ 563,18 = R$ 3.379,08\n Matrículas realizadas até em FEVEREIRO: 5 mensalidades de R$ 675,81 = R$ 3.379,08\nMatrículas realizadas até MARÇO: 04 mensalidades R$ 844,77 = R$ 3.3.79,08\n\nInício das aulas em Fevereiro de 2026 📚📖","time":"13/01/2026 09:10:18","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"client","text":"Esse valor de 563 é durante todo o curso?","time":"13/01/2026 09:11:34"},{"role":"agent","text":"*Karina Pimentel:* Isso mesmo. Realizando os pagamentos até o dia 10 de todo mês, os descontos serão mantidos!","time":"13/01/2026 09:13:29","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Karina Pimentel:*  Ficou alguma dúvida? O que está faltando para você dar esse passo e ingressar no curso? Tenho certeza de que será transformador em sua vida. 😊","time":"13/01/2026 16:22:16","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"client","text":"Atendimento Finalizado!\n\nðŸ§ðŸ½â€â™‚ï¸, esperamos que sua solicitação tenha sido totalmente resolvida.\n\nO seu feedback é muito importante para nós, então agradecemos se puder avaliar nosso atendimento em uma pesquisa futura.\n\nA FICV agradece o seu contato. Estamos sempre à disposição!","time":"14/01/2026 08:17:54"},{"role":"client","text":"Sua sessão irá expirar em 2 minutos!","time":"16/01/2026 09:09:35"},{"role":"client","text":"Sua sessão expirou!","time":"16/01/2026 09:11:38"}]$tag$, $tag$2026-01-13 09:06:08+00$tag$, FALSE, FALSE, 6.6, $tag$2026-03-01 16:46:57.607947+00$tag$, 5, 10, 7, 2, 9, 4, $tag$65b591e2-df83-4fd5-9de1-52b0445d3ed1$tag$, $tag$approved$tag$, TRUE, NULL, '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET protocol = EXCLUDED.protocol, contact = EXCLUDED.contact, agent_id = EXCLUDED.agent_id, agent_name = EXCLUDED.agent_name, message_content = EXCLUDED.message_content, timestamp = EXCLUDED.timestamp, has_empathy = EXCLUDED.has_empathy, closing_attempt = EXCLUDED.closing_attempt, final_score = EXCLUDED.final_score, created_at = EXCLUDED.created_at, empathy_score = EXCLUDED.empathy_score, clarity_score = EXCLUDED.clarity_score, depth_score = EXCLUDED.depth_score, commercial_score = EXCLUDED.commercial_score, agility_score = EXCLUDED.agility_score, message_count = EXCLUDED.message_count, upload_id = EXCLUDED.upload_id, status = EXCLUDED.status, is_commercial = EXCLUDED.is_commercial, overall_conclusion = EXCLUDED.overall_conclusion, improvements = EXCLUDED.improvements;
INSERT INTO public.messages_logs (id, protocol, contact, agent_id, agent_name, message_content, timestamp, has_empathy, closing_attempt, final_score, created_at, empathy_score, clarity_score, depth_score, commercial_score, agility_score, message_count, upload_id, status, is_commercial, overall_conclusion, improvements) VALUES ($tag$3c6686c8-0d22-4e35-b0b4-0b75bc78dc4f$tag$, $tag$2026011300028$tag$, $tag$Patrícia Monteiro (5561983023408)$tag$, NULL, $tag$Karina Pimentel$tag$, $tag$[{"role":"client","text":"Oi, já preenchi meus dados na página Teologia EAD e quero mais informações.\n\nConclui o curso pelo Seminário Batista Nacional, e quero saber se eu posso só fazer um complemento para receber o diploma?","time":"13/01/2026 09:39:42"},{"role":"client","text":"Por favor aguarde, em breve uma das nossas Consultoras lhe passará todas as informações.","time":"13/01/2026 09:39:43"},{"role":"client","text":"Seja bem-vindo à Cidade Viva. Sou Karina Pimentel","time":"13/01/2026 09:45:47"},{"role":"client","text":"Olá Karina, bom dia!","time":"13/01/2026 09:46:23"},{"role":"agent","text":"*Karina Pimentel:*  A nossa *Graduação em Teologia EAD* é Bacharelado reconhecido pelo MEC ( *bit.ly/3LlEgJS* ), com a duração de 3 anos.\n\nNo formato EAD, as aulas são ao vivo e gravadas e ficam à disposição do aluno no Ambiente Virtual de Aprendizagem, para assistir no seu tempo. As aulas ao vivo terão dia e horário definidos previamente e poderão ser assistidas posteriormente, pois ficarão gravadas.\n\nO aluno tem acesso aos materiais disponibilizados por nossos professores, tem encontros remotos com tutores, através da Plataforma Virtual da FICV (Plataforma Moodle), além de contar com materiais de apoio acadêmico-científico.","time":"13/01/2026 09:46:24","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Karina Pimentel:* \n 🎓 Graduação EAD em Teologia por apenas R$ 399,70/mês! 🤩 Aproveite a condição especial: 10% de desconto na pontualidade durante toda a graduação, reduzindo o valor para R$ 359,73 por mês! 🎉 Usando o cupom *BOLSA10*\n\n✨ Sem taxa de matrícula! A primeira mensalidade é paga no ato da inscrição, e a próxima apenas no mês de início das aulas.\n\n💥 Valor promocional: Semestralidade por R$ 2.158,38!\n\n⚠ Atenção: O valor mensal pode variar de acordo com a data de matrícula:\n\nMatrículas realizadas até em JANEIRO: 6 mensalidades de R$ 359,73 = R$ 2.158,38\nMatrículas realizadas até em FEVEREIRO: 5 mensalidades de R$  431,67 = R$2.158,38\nMatrículas realizadas até MARÇO: 04 mensalidades R$ 539,59 = R$ 2.158,38\n\n🗓️ Início das aulas: Fevereiro de 2026 📚💻","time":"13/01/2026 09:46:43","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"client","text":"Conclui o curso de Bacharel em Teologia pelo Seminário Batista Nacional em 30/03/2021 e quero saber se é possível fazer um complemento para receber o diploma reconhecido pelo MEC..","time":"13/01/2026 09:50:11"},{"role":"agent","text":"*Karina Pimentel:* Não realizamos convalidação! ","time":"13/01/2026 10:58:01","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"client","text":"Que pena! \nObrigada!","time":"13/01/2026 10:59:22"},{"role":"agent","text":"*Karina Pimentel:* Espero ter atendido sua demanda. Caso tenha alguma outra dúvida ou solicitação, não hesite em entrar em contato novamente. Deus te abençoe. 😊","time":"13/01/2026 16:23:33","feedback":"🚩 Fechamento Ausente: O contato está terminando. Sempre faça um convite para o próximo passo."},{"role":"client","text":"Atendimento Finalizado!\n\nPatrícia Monteiro, esperamos que sua solicitação tenha sido totalmente resolvida.\n\nO seu feedback é muito importante para nós, então agradecemos se puder avaliar nosso atendimento em uma pesquisa futura.\n\nA FICV agradece o seu contato. Estamos sempre à disposição!","time":"13/01/2026 16:23:36"},{"role":"client","text":"Sua sessão irá expirar em 2 minutos!","time":"16/01/2026 10:57:24"},{"role":"client","text":"Sua sessão expirou!","time":"16/01/2026 10:59:25"}]$tag$, $tag$2026-01-13 09:39:42+00$tag$, FALSE, FALSE, 7, $tag$2026-03-01 16:46:57.607947+00$tag$, 9, 10, 5, 2, 9, 4, $tag$65b591e2-df83-4fd5-9de1-52b0445d3ed1$tag$, $tag$approved$tag$, TRUE, NULL, '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET protocol = EXCLUDED.protocol, contact = EXCLUDED.contact, agent_id = EXCLUDED.agent_id, agent_name = EXCLUDED.agent_name, message_content = EXCLUDED.message_content, timestamp = EXCLUDED.timestamp, has_empathy = EXCLUDED.has_empathy, closing_attempt = EXCLUDED.closing_attempt, final_score = EXCLUDED.final_score, created_at = EXCLUDED.created_at, empathy_score = EXCLUDED.empathy_score, clarity_score = EXCLUDED.clarity_score, depth_score = EXCLUDED.depth_score, commercial_score = EXCLUDED.commercial_score, agility_score = EXCLUDED.agility_score, message_count = EXCLUDED.message_count, upload_id = EXCLUDED.upload_id, status = EXCLUDED.status, is_commercial = EXCLUDED.is_commercial, overall_conclusion = EXCLUDED.overall_conclusion, improvements = EXCLUDED.improvements;
INSERT INTO public.messages_logs (id, protocol, contact, agent_id, agent_name, message_content, timestamp, has_empathy, closing_attempt, final_score, created_at, empathy_score, clarity_score, depth_score, commercial_score, agility_score, message_count, upload_id, status, is_commercial, overall_conclusion, improvements) VALUES ($tag$834bd318-ee1e-4ade-bbd9-622c369a9fca$tag$, $tag$2026011300049$tag$, $tag$Paulo José (5561981725220)$tag$, NULL, $tag$Karina Pimentel$tag$, $tag$[{"role":"client","text":"Oi, já preenchi meus dados na página Teologia Novo Testamento e quero mais informações.","time":"13/01/2026 10:58:05"},{"role":"client","text":"🌟 Bom dia Paulo José! Que alegria ter você aqui com a gente! 🙌","time":"13/01/2026 10:58:06"},{"role":"client","text":"Seja bem-vindo ao atendimento digital da Cidade Viva","time":"13/01/2026 10:58:10"},{"role":"client","text":"Você poderá tirar dúvidas sobre Igreja, Faculdade, Fundação, Livraria e nosso Sistema de Ensino.\n","time":"13/01/2026 10:58:14"},{"role":"client","text":"🔐 *Em conformidade com a Lei Geral de Proteção de Dados (LGPD), seus dados serão utilizados exclusivamente para fins de atendimento, tratados com segurança e nunca compartilhados com terceiros sem sua autorização.*","time":"13/01/2026 10:58:18"},{"role":"client","text":"Antes de seguirmos, pedimos apenas um minuto para conferir nossos Termos de Uso e Política de Privacidade. Neles, você encontra todos os detalhes sobre como tratamos seus dados em conformidade com a LGPD, seja para assuntos da Igreja, Escola, Fundação ou outras áreas da organização.","time":"13/01/2026 10:58:24"},{"role":"client","text":"Acesse o documento completo aqui: https://drive.google.com/file/d/1k1z1zHcYSVRfRcy8ZH_jridrI2xRP-en/view?usp=sharing \n\n✅ Ao continuar neste atendimento, você declara estar ciente e de acordo com estes termos.","time":"13/01/2026 10:58:30"},{"role":"client","text":"Você concorda com o uso dos seus dados conforme informado acima?","time":"13/01/2026 10:58:31"},{"role":"client","text":"Sim, concordo","time":"13/01/2026 11:02:38"},{"role":"client","text":"✅ Obrigado, Paulo José! Agora que você concordou com os termos da LGPD, podemos continuar seu atendimento. ","time":"13/01/2026 11:02:39"},{"role":"client","text":"Agora, selecione no menu abaixo com qual área da Cidade Viva você deseja falar.","time":"13/01/2026 11:02:44"},{"role":"client","text":"Faculdade \n Faculdade Internacional Cidade Viva","time":"13/01/2026 11:03:30"},{"role":"client","text":"Olá! Paulo José!👋\n É um prazer te receber aqui, na Faculdade Internacional Cidade Viva. 😊","time":"13/01/2026 11:03:31"},{"role":"client","text":"Escolha uma opção abaixo para continuarmos:","time":"13/01/2026 11:03:35"},{"role":"client","text":"Saber sobre os cursos","time":"13/01/2026 11:04:02"},{"role":"client","text":"Perfeito! Qual modalidade de curso você tem interesse?","time":"13/01/2026 11:04:07"},{"role":"client","text":"Pós-Graduação","time":"13/01/2026 11:08:57"},{"role":"client","text":"Esses são os cursos de *Pós-Graduação* que temos disponíveis no momento:","time":"13/01/2026 11:09:02"},{"role":"client","text":"Pós-graduação em\nTeologia Bíblica e\nexegética do Novo Testamento","time":"13/01/2026 11:09:52"},{"role":"client","text":"Desculpe, não entendi a opção desejada.\nPor favor, selecione no menu abaixo a opção que mais adequa a sua necessidade.","time":"13/01/2026 11:09:54"},{"role":"client","text":"Esses são os cursos de *Pós-Graduação* que temos disponíveis no momento:","time":"13/01/2026 11:09:58"},{"role":"client","text":"Novo Testamento","time":"13/01/2026 11:10:16"},{"role":"client","text":"Estude profundamente o contexto, a teologia e a mensagem do Novo Testamento.\n\n 🔠 Com Grego Bíblico, exegese e interpretação textual\n 📚 Ideal para pastores, líderes e estudiosos da Bíblia\n 📅 Comece sua formação teológica ainda este ano\n","time":"13/01/2026 11:10:17"},{"role":"client","text":"Quer receber mais detalhes ou falar com um consultor?","time":"13/01/2026 11:10:21"},{"role":"client","text":"Quero saber mais \n Quero saber mais detalhes.","time":"13/01/2026 11:10:49"},{"role":"client","text":"Certo, em alguns instantes um dos nossos Consultores falará contigo.\nFique à vontade para interagir ou fazer alguma pergunta, OK?","time":"13/01/2026 11:10:50"},{"role":"client","text":"Seja bem-vindo à Cidade Viva. Sou Karina Pimentel","time":"13/01/2026 11:28:59"},{"role":"agent","text":"*Karina Pimentel:* *Pós-graduação em Teologia Bíblica e Exegética do Novo Testamento*\n\n*NOTA MÁXIMA NO MEC*\nPós-graduação com a maior avaliação junto ao MEC, conceito 05 estrelas.\n\n*DURAÇÃO*\nO curso tem duração de 16 meses.\n\n*CARGA HORÁRIA*\nNossa carga horária é de 440h.\n\n*DISCIPLINAS*\nContamos com um total de 12 disciplinas.\n\n*AULAS*\nO curso é totalmente on-line e você pode assistir às aulas em qualquer dia e horário, pois ficarão gravadas dentro da plataforma.\n\n*AVALIAÇÕES*\nAs avaliações serão realizadas através de questões abertas, fechadas, fóruns e elaboração de textos. Todas as atividades serão realizadas dentro da plataforma educacional, assim, não é necessário ter um Polo da Faculdade em sua cidade.\n\n*NÃO É NECESSÁRIO TCC*\nDe acordo com a nova deliberação do MEC, a Resolução CNE/CES nº 1/2018, não há mais a obrigação de entrega de um TCC.","time":"14/01/2026 08:13:38","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Karina Pimentel:* O valor de investimento na Pós-graduação em Novo Testamento está em 16 mensalidades de *R$ 359,37.\n\nNão temos taxa de matrícula. Ao pagar a primeira mensalidade hoje, as próximas serão devidas a partir do início das aulas, previsto para Abril.","time":"14/01/2026 08:14:20","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"client","text":"Atendimento Finalizado!\n\nPaulo José, esperamos que sua solicitação tenha sido totalmente resolvida.\n\nO seu feedback é muito importante para nós, então agradecemos se puder avaliar nosso atendimento em uma pesquisa futura.\n\nA FICV agradece o seu contato. Estamos sempre à disposição!","time":"15/01/2026 10:54:17"},{"role":"client","text":"Sua opinião é muito importante para nós.\nPor gentileza, avalie o atendimento realizado, considerando 1 como muito insatisfeito e 5 como muito satisfeito.","time":"15/01/2026 10:54:18"},{"role":"client","text":"Paulo José, Obrigado pelo seu interesse na Cidade Viva.\n\nCaso deseje outra informação, não hesite em entrar em contato com a gente!\n  \nAté mais!","time":"15/01/2026 11:09:19"}]$tag$, $tag$2026-01-13 10:58:05+00$tag$, FALSE, FALSE, 8.2, $tag$2026-03-01 16:46:57.607947+00$tag$, 10, 10, 10, 2, 9, 2, $tag$65b591e2-df83-4fd5-9de1-52b0445d3ed1$tag$, $tag$approved$tag$, TRUE, NULL, '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET protocol = EXCLUDED.protocol, contact = EXCLUDED.contact, agent_id = EXCLUDED.agent_id, agent_name = EXCLUDED.agent_name, message_content = EXCLUDED.message_content, timestamp = EXCLUDED.timestamp, has_empathy = EXCLUDED.has_empathy, closing_attempt = EXCLUDED.closing_attempt, final_score = EXCLUDED.final_score, created_at = EXCLUDED.created_at, empathy_score = EXCLUDED.empathy_score, clarity_score = EXCLUDED.clarity_score, depth_score = EXCLUDED.depth_score, commercial_score = EXCLUDED.commercial_score, agility_score = EXCLUDED.agility_score, message_count = EXCLUDED.message_count, upload_id = EXCLUDED.upload_id, status = EXCLUDED.status, is_commercial = EXCLUDED.is_commercial, overall_conclusion = EXCLUDED.overall_conclusion, improvements = EXCLUDED.improvements;
INSERT INTO public.messages_logs (id, protocol, contact, agent_id, agent_name, message_content, timestamp, has_empathy, closing_attempt, final_score, created_at, empathy_score, clarity_score, depth_score, commercial_score, agility_score, message_count, upload_id, status, is_commercial, overall_conclusion, improvements) VALUES ($tag$1b8b9dcd-6c1e-4fa1-b4a4-65f5544ef9f2$tag$, $tag$2026011300067$tag$, $tag$andreiacarvalho647 (5555997338214)$tag$, NULL, $tag$Karina Pimentel$tag$, $tag$[{"role":"client","text":"Oi, já preenchi meus dados na página Teologia EAD e quero mais informações.","time":"13/01/2026 13:24:44"},{"role":"client","text":"Por favor aguarde, em breve uma das nossas Consultoras lhe passará todas as informações.","time":"13/01/2026 13:24:45"},{"role":"client","text":"Seja bem-vindo à Cidade Viva. Sou Karina Pimentel","time":"13/01/2026 13:26:47"},{"role":"agent","text":"*Karina Pimentel:* A nossa *Graduação em Teologia EAD* é Bacharelado reconhecido pelo MEC ( *bit.ly/3LlEgJS* ), com a duração de 3 anos.\n\nNo formato EAD, as aulas são ao vivo e gravadas e ficam à disposição do aluno no Ambiente Virtual de Aprendizagem, para assistir no seu tempo. As aulas ao vivo terão dia e horário definidos previamente e poderão ser assistidas posteriormente, pois ficarão gravadas.\n\nO aluno tem acesso aos materiais disponibilizados por nossos professores, tem encontros remotos com tutores, através da Plataforma Virtual da FICV (Plataforma Moodle), além de contar com materiais de apoio acadêmico-científico.","time":"13/01/2026 13:27:14","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Karina Pimentel:* 🎓 Graduação EAD em Teologia por apenas R$ 399,70/mês! 🤩 Aproveite a condição especial: 10% de desconto na pontualidade durante toda a graduação, reduzindo o valor para R$ 359,73 por mês! 🎉 Usando o cupom *BOLSA10*\n\n✨ Sem taxa de matrícula! A primeira mensalidade é paga no ato da inscrição, e a próxima apenas no mês de início das aulas.\n\n💥 Valor promocional: Semestralidade por R$ 2.158,38!\n\n⚠ Atenção: O valor mensal pode variar de acordo com a data de matrícula:\n\nMatrículas realizadas até em JANEIRO: 6 mensalidades de R$ 359,73 = R$ 2.158,38\nMatrículas realizadas até em FEVEREIRO: 5 mensalidades de R$  431,67 = R$2.158,38\nMatrículas realizadas até MARÇO: 04 mensalidades R$ 539,59 = R$ 2.158,38\n\n🗓️ Início das aulas: Fevereiro de 2026 📚💻","time":"13/01/2026 13:27:38","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Karina Pimentel:*  \n Bom dia! Ficou alguma dúvida? O que está faltando para você dar esse passo e ingressar no curso? Tenho certeza de que será transformador em sua vida. 😊","time":"14/01/2026 08:15:24","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"client","text":"Atendimento Finalizado!\n\nandreiacarvalho647, esperamos que sua solicitação tenha sido totalmente resolvida.\n\nO seu feedback é muito importante para nós, então agradecemos se puder avaliar nosso atendimento em uma pesquisa futura.\n\nA FICV agradece o seu contato. Estamos sempre à disposição!","time":"15/01/2026 10:54:25"},{"role":"client","text":"Sua sessão irá expirar em 2 minutos!","time":"16/01/2026 13:24:47"},{"role":"client","text":"Sua sessão expirou!","time":"16/01/2026 13:26:49"}]$tag$, $tag$2026-01-13 13:24:44+00$tag$, FALSE, FALSE, 6.6, $tag$2026-03-01 16:46:57.607947+00$tag$, 7, 10, 5, 2, 9, 3, $tag$65b591e2-df83-4fd5-9de1-52b0445d3ed1$tag$, $tag$approved$tag$, TRUE, NULL, '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET protocol = EXCLUDED.protocol, contact = EXCLUDED.contact, agent_id = EXCLUDED.agent_id, agent_name = EXCLUDED.agent_name, message_content = EXCLUDED.message_content, timestamp = EXCLUDED.timestamp, has_empathy = EXCLUDED.has_empathy, closin