INSERT INTO public.messages_logs (id, protocol, contact, agent_id, agent_name, message_content, timestamp, has_empathy, closing_attempt, final_score, created_at, empathy_score, clarity_score, depth_score, commercial_score, agility_score, message_count, upload_id, status, is_commercial, overall_conclusion, improvements) VALUES ($tag$855aedbb-d6b5-49e3-9f4d-b4cab3ff55b6$tag$, $tag$2026011300112$tag$, $tag$Fayruse Medeiros (5584999148084)$tag$, NULL, $tag$Thayanne Sales$tag$, $tag$[{"role":"client","text":"Boa tarde","time":"13/01/2026 17:30:15"},{"role":"client","text":"🌟 Boa tarde Fayruse Medeiros! Que alegria ter você aqui com a gente! 🙌","time":"13/01/2026 17:30:17"},{"role":"client","text":"Seja bem-vindo ao atendimento digital da Cidade Viva","time":"13/01/2026 17:30:20"},{"role":"client","text":"Você poderá tirar dúvidas sobre Igreja, Faculdade, Fundação, Livraria e nosso Sistema de Ensino.\n","time":"13/01/2026 17:30:24"},{"role":"client","text":"🔐 *Em conformidade com a Lei Geral de Proteção de Dados (LGPD), seus dados serão utilizados exclusivamente para fins de atendimento, tratados com segurança e nunca compartilhados com terceiros sem sua autorização.*","time":"13/01/2026 17:30:28"},{"role":"client","text":"Antes de seguirmos, pedimos apenas um minuto para conferir nossos Termos de Uso e Política de Privacidade. Neles, você encontra todos os detalhes sobre como tratamos seus dados em conformidade com a LGPD, seja para assuntos da Igreja, Escola, Fundação ou outras áreas da organização.","time":"13/01/2026 17:30:33"},{"role":"client","text":"Acesse o documento completo aqui: https://drive.google.com/file/d/1k1z1zHcYSVRfRcy8ZH_jridrI2xRP-en/view?usp=sharing \n\n✅ Ao continuar neste atendimento, você declara estar ciente e de acordo com estes termos.","time":"13/01/2026 17:30:39"},{"role":"client","text":"Você concorda com o uso dos seus dados conforme informado acima?","time":"13/01/2026 17:30:40"},{"role":"client","text":"Sim, concordo","time":"13/01/2026 17:31:05"},{"role":"client","text":"✅ Obrigado, Fayruse Medeiros! Agora que você concordou com os termos da LGPD, podemos continuar seu atendimento. ","time":"13/01/2026 17:31:06"},{"role":"client","text":"Agora, selecione no menu abaixo com qual área da Cidade Viva você deseja falar.","time":"13/01/2026 17:31:09"},{"role":"client","text":"Faculdade \n Faculdade Internacional Cidade Viva","time":"13/01/2026 17:31:24"},{"role":"client","text":"Olá! Fayruse Medeiros!👋\n É um prazer te receber aqui, na Faculdade Internacional Cidade Viva. 😊","time":"13/01/2026 17:31:24"},{"role":"client","text":"Escolha uma opção abaixo para continuarmos:","time":"13/01/2026 17:31:28"},{"role":"client","text":"Saber sobre os cursos","time":"13/01/2026 17:31:43"},{"role":"client","text":"Perfeito! Qual modalidade de curso você tem interesse?","time":"13/01/2026 17:31:48"},{"role":"client","text":"Graduação","time":"13/01/2026 17:31:59"},{"role":"client","text":"Esses são os cursos de Graduação que temos disponíveis no momento:","time":"13/01/2026 17:32:03"},{"role":"client","text":"Direito (Presencial)","time":"13/01/2026 17:32:13"},{"role":"client","text":"Excelente escolha! O curso de Direito da FICV é presencial em João Pessoa, tem nota máxima no MEC, prática jurídica desde o primeiro período e bolsa de 60% em todas as mensalidades!\n","time":"13/01/2026 17:32:15"},{"role":"client","text":"Quer receber mais detalhes ou falar com um consultor?","time":"13/01/2026 17:32:19"},{"role":"client","text":"Quero saber mais \n Quero saber mais detalhes.","time":"13/01/2026 17:32:40"},{"role":"client","text":"Certo, em alguns instantes um dos nossos Consultores falará contigo.\nFique à vontade para interagir ou fazer alguma pergunta, OK?","time":"13/01/2026 17:32:40"},{"role":"client","text":"Seja bem-vindo à Cidade Viva. Sou Thayanne Sales","time":"13/01/2026 17:34:59"},{"role":"agent","text":"*Thayanne Sales:* Vou lhe enviar as informações sobre o curso","time":"13/01/2026 17:35:13","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Thayanne Sales:* *Bacharelado em Direito*\n\n*GRADUAÇÃO COM COSMOVISÃO CRISTÃ*\nValorização do Direito clássico, sem viés ideológico, o Direito tratado numa cosmovisão cristã.\n\n*NOTA MÁXIMA NO MEC*\nGraduação com a maior avaliação junto ao MEC, conceito 05 estrelas ( *bit.ly/3LlEgJS* ) com duração de 5 anos. \n\n*PRÁTICA JURÍDICA*\nÚnico curso no Brasil com vivência de prática jurídica do primeiro ao décimo período.\n\n*NÚCLEO*\nPrimeiro e único núcleo de prática jurídica em Lei Geral de Proteção de Dados (LGPD).\n\n*VOCAÇÃO*\nEspecialização durante a graduação com disciplinas optativas nas áreas: \n\na) Serviço Público; \nb) Advocacia Empreendedora; \nc) Academia\n\n*BIBLIOTECA DIGITAL*\nRevista dos Tribunais online e a Biblioteca Digital Proview da Revista dos Tribunais. Kindles com assinatura Unlimited.\n\n*AULAS PRESENCIAIS*\nDe segunda à sexta, das 19h às 22h - goo.gl/maps/tb5occMvgJGHsjwz9.","time":"13/01/2026 17:35:23","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Thayanne Sales:*  Segue a matriz curricular do curso de Direito *bit.ly/3SpepqX*","time":"13/01/2026 17:35:28","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Thayanne Sales:* A mensalidade da Graduação em Direito está R$ 1.407,95. \n\n🤩 Estamos com uma condição excepcional, desconto de 60% na pontualidade durante toda graduação que ficará o valor de R$ 563,18.\n\nNão há taxa de matrícula, sendo a primeira mensalidade paga no ato da inscrição, e as demais mensalidades pagas até o dia 10 de cada mês.\n\n🌟 Valor promocional: (Semestralidade R$ 3.379,08).\n⚠️ Valor mensal está sujeito a mudança de acordo a data de matrícula:\n\n Matrículas realizadas até em JANEIRO: 6 mensalidades de R$ 563,18 = R$ 3.379,08\n Matrículas realizadas até em FEVEREIRO: 5 mensalidades de R$ 675,81 = R$ 3.379,08\nMatrículas realizadas até MARÇO: 04 mensalidades R$ 844,77 = R$ 3.3.79,08\n\nInício das aulas em Fevereiro de 2026 📚📖💻","time":"13/01/2026 17:35:34","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Thayanne Sales:* ✅ PROCEDIMENTO DE MATRÍCULA:\n\nRealize a matrícula de acordo com a sua forma de ingresso, basta acessar o link correspondente abaixo:\n\n1 - Aproveitamento do ENEM:\nbit.ly/FICV-Enem\n\n2 - Vestibular Agendado:\nbit.ly/FICV-Vestibular\n\n3 - Seleção de Graduados:\nbit.ly/FICV-Graduados\n\n📝 Após preencher seus dados, o sistema disponibilizará o pagamento da primeira parcela e o contrato para aceite. Não há cobrança de matrícula.😊","time":"13/01/2026 17:35:40","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"client","text":"Aceita transferência de outra faculdade?","time":"13/01/2026 17:37:26"},{"role":"agent","text":"*Thayanne Sales:* Sim","time":"13/01/2026 17:37:53","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Thayanne Sales:*   📌 Para realizar o aproveitamento de disciplinas você enviará o Requerimento de Aproveitamento de Estudos preenchido ( *https://bit.ly/Aproveitamento-FICV* ), junto com o histórico e o ementário das disciplinas desejadas para o e-mail:\n\nfaculdade@cidadeviva.org\n\nCom o assunto: Aproveitamento de disciplinas.","time":"13/01/2026 17:37:54","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Thayanne Sales:* Olá Bom dia! Tudo bom?\nQue alegria falar com você! 👋🏼\n\nConseguiu fazer a sua matricula?","time":"14/01/2026 08:20:47","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"client","text":"Atendimento Finalizado!\n\nFayruse Medeiros, esperamos que sua solicitação tenha sido totalmente resolvida.\n\nO seu feedback é muito importante para nós, então agradecemos se puder avaliar nosso atendimento em uma pesquisa futura.\n\nA FICV agradece o seu contato. Estamos sempre à disposição!","time":"14/01/2026 17:39:11"},{"role":"client","text":"Sua opinião é muito importante para nós.\nPor gentileza, avalie o atendimento realizado, considerando 1 como muito insatisfeito e 5 como muito satisfeito.","time":"14/01/2026 17:39:12"},{"role":"client","text":"Fayruse Medeiros, Obrigado pelo seu interesse na Cidade Viva.\n\nCaso deseje outra informação, não hesite em entrar em contato com a gente!\n  \nAté mais!","time":"14/01/2026 17:54:13"}]$tag$, $tag$2026-01-13 17:30:15+00$tag$, FALSE, FALSE, 8.2, $tag$2026-03-01 16:46:57.607947+00$tag$, 10, 10, 10, 2, 9, 8, $tag$65b591e2-df83-4fd5-9de1-52b0445d3ed1$tag$, $tag$approved$tag$, TRUE, NULL, '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET protocol = EXCLUDED.protocol, contact = EXCLUDED.contact, agent_id = EXCLUDED.agent_id, agent_name = EXCLUDED.agent_name, message_content = EXCLUDED.message_content, timestamp = EXCLUDED.timestamp, has_empathy = EXCLUDED.has_empathy, closing_attempt = EXCLUDED.closing_attempt, final_score = EXCLUDED.final_score, created_at = EXCLUDED.created_at, empathy_score = EXCLUDED.empathy_score, clarity_score = EXCLUDED.clarity_score, depth_score = EXCLUDED.depth_score, commercial_score = EXCLUDED.commercial_score, agility_score = EXCLUDED.agility_score, message_count = EXCLUDED.message_count, upload_id = EXCLUDED.upload_id, status = EXCLUDED.status, is_commercial = EXCLUDED.is_commercial, overall_conclusion = EXCLUDED.overall_conclusion, improvements = EXCLUDED.improvements;
INSERT INTO public.messages_logs (id, protocol, contact, agent_id, agent_name, message_content, timestamp, has_empathy, closing_attempt, final_score, created_at, empathy_score, clarity_score, depth_score, commercial_score, agility_score, message_count, upload_id, status, is_commercial, overall_conclusion, improvements) VALUES ($tag$5737d1a8-374b-41f8-9311-37593a843d5d$tag$, $tag$2026011300129$tag$, $tag$Mirele De Melo (5534997061753)$tag$, NULL, $tag$Karina Pimentel$tag$, $tag$[{"role":"client","text":"Oi, já preenchi meus dados na página Teologia EAD e quero mais informações.","time":"13/01/2026 20:44:40"},{"role":"client","text":"Por favor aguarde, em breve uma das nossas Consultoras lhe passará todas as informações.","time":"13/01/2026 20:44:41"},{"role":"client","text":"Seja bem-vindo à Cidade Viva. Sou Karina Pimentel","time":"14/01/2026 07:58:58"},{"role":"agent","text":"*Karina Pimentel:* A nossa *Graduação em Teologia EAD* é Bacharelado reconhecido pelo MEC ( *bit.ly/3LlEgJS* ), com a duração de 3 anos.\n\nNo formato EAD, as aulas são ao vivo e gravadas e ficam à disposição do aluno no Ambiente Virtual de Aprendizagem, para assistir no seu tempo. As aulas ao vivo terão dia e horário definidos previamente e poderão ser assistidas posteriormente, pois ficarão gravadas.\n\nO aluno tem acesso aos materiais disponibilizados por nossos professores, tem encontros remotos com tutores, através da Plataforma Virtual da FICV (Plataforma Moodle), além de contar com materiais de apoio acadêmico-científico.","time":"14/01/2026 07:59:26","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Karina Pimentel:* 🎓 Graduação EAD em Teologia por apenas R$ 399,70/mês! 🤩 Aproveite a condição especial: 10% de desconto na pontualidade durante toda a graduação, reduzindo o valor para R$ 359,73 por mês! 🎉 Usando o cupom *BOLSA10*\n\n✨ Sem taxa de matrícula! A primeira mensalidade é paga no ato da inscrição, e a próxima apenas no mês de início das aulas.\n\n💥 Valor promocional: Semestralidade por R$ 2.158,38!\n\n⚠ Atenção: O valor mensal pode variar de acordo com a data de matrícula:\n\nMatrículas realizadas até em JANEIRO: 6 mensalidades de R$ 359,73 = R$ 2.158,38\nMatrículas realizadas até em FEVEREIRO: 5 mensalidades de R$  431,67 = R$2.158,38\nMatrículas realizadas até MARÇO: 04 mensalidades R$ 539,59 = R$ 2.158,38\n\n🗓️ Início das aulas: Fevereiro de 2026 📚💻","time":"14/01/2026 07:59:47","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"client","text":"Atendimento Finalizado!\n\nMirele De Melo, esperamos que sua solicitação tenha sido totalmente resolvida.\n\nO seu feedback é muito importante para nós, então agradecemos se puder avaliar nosso atendimento em uma pesquisa futura.\n\nA FICV agradece o seu contato. Estamos sempre à disposição!","time":"15/01/2026 10:51:12"},{"role":"client","text":"Sua sessão irá expirar em 2 minutos!","time":"17/01/2026 07:57:00"},{"role":"client","text":"Sua sessão expirou!","time":"17/01/2026 07:59:01"}]$tag$, $tag$2026-01-13 20:44:40+00$tag$, FALSE, FALSE, 5.8, $tag$2026-03-01 16:46:57.607947+00$tag$, 5, 10, 3, 2, 9, 2, $tag$65b591e2-df83-4fd5-9de1-52b0445d3ed1$tag$, $tag$approved$tag$, TRUE, NULL, '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET protocol = EXCLUDED.protocol, contact = EXCLUDED.contact, agent_id = EXCLUDED.agent_id, agent_name = EXCLUDED.agent_name, message_content = EXCLUDED.message_content, timestamp = EXCLUDED.timestamp, has_empathy = EXCLUDED.has_empathy, closing_attempt = EXCLUDED.closing_attempt, final_score = EXCLUDED.final_score, created_at = EXCLUDED.created_at, empathy_score = EXCLUDED.empathy_score, clarity_score = EXCLUDED.clarity_score, depth_score = EXCLUDED.depth_score, commercial_score = EXCLUDED.commercial_score, agility_score = EXCLUDED.agility_score, message_count = EXCLUDED.message_count, upload_id = EXCLUDED.upload_id, status = EXCLUDED.status, is_commercial = EXCLUDED.is_commercial, overall_conclusion = EXCLUDED.overall_conclusion, improvements = EXCLUDED.improvements;
INSERT INTO public.messages_logs (id, protocol, contact, agent_id, agent_name, message_content, timestamp, has_empathy, closing_attempt, final_score, created_at, empathy_score, clarity_score, depth_score, commercial_score, agility_score, message_count, upload_id, status, is_commercial, overall_conclusion, improvements) VALUES ($tag$1da871a6-f1d8-4530-b3b6-ca008b6d1925$tag$, $tag$2026011300134$tag$, $tag$Não identificado (5583986549181)$tag$, NULL, $tag$Karina Pimentel$tag$, $tag$[{"role":"client","text":"Oi, já preenchi meus dados na página Teologia EAD e quero mais informações.","time":"13/01/2026 21:55:26"},{"role":"client","text":"Por favor aguarde, em breve uma das nossas Consultoras lhe passará todas as informações.","time":"13/01/2026 21:55:27"},{"role":"client","text":"Seja bem-vindo à Cidade Viva. Sou Karina Pimentel","time":"14/01/2026 08:02:58"},{"role":"agent","text":"*Karina Pimentel:*  A nossa *Graduação em Teologia EAD* é Bacharelado reconhecido pelo MEC ( *bit.ly/3LlEgJS* ), com a duração de 3 anos.\n\nNo formato EAD, as aulas são ao vivo e gravadas e ficam à disposição do aluno no Ambiente Virtual de Aprendizagem, para assistir no seu tempo. As aulas ao vivo terão dia e horário definidos previamente e poderão ser assistidas posteriormente, pois ficarão gravadas.\n\nO aluno tem acesso aos materiais disponibilizados por nossos professores, tem encontros remotos com tutores, através da Plataforma Virtual da FICV (Plataforma Moodle), além de contar com materiais de apoio acadêmico-científico.","time":"14/01/2026 08:03:26","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Karina Pimentel:* 🎓 Graduação EAD em Teologia por apenas R$ 399,70/mês! 🤩 Aproveite a condição especial: 10% de desconto na pontualidade durante toda a graduação, reduzindo o valor para R$ 359,73 por mês! 🎉 Usando o cupom *BOLSA10*\n\n✨ Sem taxa de matrícula! A primeira mensalidade é paga no ato da inscrição, e a próxima apenas no mês de início das aulas.\n\n💥 Valor promocional: Semestralidade por R$ 2.158,38!\n\n⚠ Atenção: O valor mensal pode variar de acordo com a data de matrícula:\n\nMatrículas realizadas até em JANEIRO: 6 mensalidades de R$ 359,73 = R$ 2.158,38\nMatrículas realizadas até em FEVEREIRO: 5 mensalidades de R$  431,67 = R$2.158,38\nMatrículas realizadas até MARÇO: 04 mensalidades R$ 539,59 = R$ 2.158,38\n\n🗓️ Início das aulas: Fevereiro de 2026 📚💻","time":"14/01/2026 08:03:43","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"client","text":"Presencial é o mesmo valor?","time":"14/01/2026 09:56:55"},{"role":"client","text":"Pode usar a note do Enem de 2018?","time":"14/01/2026 09:57:34"},{"role":"client","text":"Posso fazer a modalidade semi presencial? Caso algum dia nao consiga ir presencial, ficam disponíveis as aulas gravadas?","time":"14/01/2026 09:58:06"},{"role":"agent","text":"*Karina Pimentel:* De até 5 anos!","time":"14/01/2026 10:02:04","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Karina Pimentel:* Vou lhe enviar ok!","time":"14/01/2026 10:02:13","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Karina Pimentel:* A nossa *Graduação em Teologia Presencial* é Bacharelado e reconhecida pelo MEC ( *bit.ly/3LlEgJS* ), com a duração de 3 anos.\n\nNo formato presencial as aulas acontecem de segunda à quinta-feira das 19h00 às 22h00 aqui no Polo João Pessoa, localizado na Rua Luzia Simões Bartoline, 50 - Aeroclube, João Pessoa-PB.\n\nA nossa base filosófica e teológica é fundamentada na cosmovisão cristã, utilizando o método histórico-gramatical para a interpretação das Sagradas Escrituras. Como Faculdade, diferenciamo-nos de um seminário, que geralmente segue um viés denominacional. Contamos com professores de diferentes tradições cristãs, como Presbiteriana, Batista, Adventista e Anglicana, valorizando assim a integridade intelectual. Todos os nossos docentes são especializados nas suas áreas de atuação.","time":"14/01/2026 10:02:32","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Karina Pimentel:* \n  A mensalidade da Graduação Presencial em Teologia fica R$ 549,56.\n\n🤩 Estamos com uma condição especial, *desconto de 10%* na pontualidade durante toda graduação, que fica apenas R$ 494,60.  *Usando o cupom de desconto: BOLSA10*\n\nNão há taxa de matrícula, sendo a primeira mensalidade paga no ato da matrícula, e as demais mensalidades pagas no dia 10 dos meses subsequentes ao início das aulas.\n\n🌟 *Valor promocional:* (Semestralidade R$ 2.967,62).\n\n⚠ *Valor mensal está sujeito a mudança de acordo a data de matrícula:*\n \nMatrículas realizadas até em JANEIRO: 6 mensalidades de R$ 494,60 = R$ 2.967,62\nMatrículas realizadas até em FEVEREIRO: 5 mensalidades de R$ 593,52 = R$ 2.967,62\nMatrículas realizadas até MARÇO: 04 mensalidades R$ 741,90  = R$ 2.967,62\n\n🗓️ Início das aulas: Fevereiro de 2026 📚💻","time":"14/01/2026 10:02:51","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"client","text":"Poxa :/","time":"14/01/2026 10:07:09"},{"role":"client","text":"Vou deixar pra o próximo ano então","time":"14/01/2026 10:07:18"},{"role":"client","text":"Na vdd vi aqui que fiz de 2021","time":"14/01/2026 10:09:48"},{"role":"client","text":"Qual a nota de corte?","time":"14/01/2026 10:09:53"},{"role":"client","text":"Daqui pra sexta vou ai fazer a matrícula","time":"14/01/2026 10:48:24"},{"role":"agent","text":"*Karina Pimentel:* Mínimo 450.(ENEM)","time":"14/01/2026 11:05:21","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Karina Pimentel:* Benção!","time":"14/01/2026 11:05:32","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Karina Pimentel:* Qualquer duvida estou a disposição!","time":"14/01/2026 11:05:46","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"client","text":"Obrigadaaa","time":"14/01/2026 11:13:52"},{"role":"client","text":"As aulas estão previstas pra começar que dia de fevereiro?","time":"14/01/2026 11:14:56"},{"role":"agent","text":"*Karina Pimentel:* 05/02.","time":"14/01/2026 11:33:24","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Karina Pimentel:*  Bom dia! Ficou alguma dúvida? O que está faltando para você dar esse passo e ingressar no curso? Tenho certeza de que será transformador em sua vida. 😊","time":"15/01/2026 10:59:31","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"client","text":"Atendimento Finalizado!\n\n, esperamos que sua solicitação tenha sido totalmente resolvida.\n\nO seu feedback é muito importante para nós, então agradecemos se puder avaliar nosso atendimento em uma pesquisa futura.\n\nA FICV agradece o seu contato. Estamos sempre à disposição!","time":"15/01/2026 10:59:35"},{"role":"client","text":"Boa tarde, tem a possibilidade de caso nao puder comparecer a algumas aulas presenciais, assiste EAD?","time":"15/01/2026 15:46:41"},{"role":"client","text":"Sua sessão irá expirar em 2 minutos!","time":"18/01/2026 15:44:42"},{"role":"client","text":"Sua sessão expirou!","time":"18/01/2026 15:46:44"}]$tag$, $tag$2026-01-13 21:55:26+00$tag$, FALSE, FALSE, 8.2, $tag$2026-03-01 16:46:57.607947+00$tag$, 10, 10, 10, 2, 9, 11, $tag$65b591e2-df83-4fd5-9de1-52b0445d3ed1$tag$, $tag$approved$tag$, TRUE, NULL, '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET protocol = EXCLUDED.protocol, contact = EXCLUDED.contact, agent_id = EXCLUDED.agent_id, agent_name = EXCLUDED.agent_name, message_content = EXCLUDED.message_content, timestamp = EXCLUDED.timestamp, has_empathy = EXCLUDED.has_empathy, closing_attempt = EXCLUDED.closing_attempt, final_score = EXCLUDED.final_score, created_at = EXCLUDED.created_at, empathy_score = EXCLUDED.empathy_score, clarity_score = EXCLUDED.clarity_score, depth_score = EXCLUDED.depth_score, commercial_score = EXCLUDED.commercial_score, agility_score = EXCLUDED.agility_score, message_count = EXCLUDED.message_count, upload_id = EXCLUDED.upload_id, status = EXCLUDED.status, is_commercial = EXCLUDED.is_commercial, overall_conclusion = EXCLUDED.overall_conclusion, improvements = EXCLUDED.improvements;
INSERT INTO public.messages_logs (id, protocol, contact, agent_id, agent_name, message_content, timestamp, has_empathy, closing_attempt, final_score, created_at, empathy_score, clarity_score, depth_score, commercial_score, agility_score, message_count, upload_id, status, is_commercial, overall_conclusion, improvements) VALUES ($tag$8f26fed1-a2aa-4ce1-a8e6-fe6658455b8e$tag$, $tag$2026011400008$tag$, $tag$Stephanne carvalho (5583996232209)$tag$, NULL, $tag$Thayanne Sales$tag$, $tag$[{"role":"client","text":"Oi, já preenchi meus dados na página Direito e quero mais informações.","time":"14/01/2026 06:10:57"},{"role":"client","text":"Por favor aguarde, em breve uma das nossas Consultoras lhe passará todas as informações.","time":"14/01/2026 06:10:58"},{"role":"client","text":"Aguarde só um momento!\n\nNeste instante, todos os nossos consultores estão prestando atendimento, o que pode gerar uma pequena espera.\n\nEstamos dedicando total atenção aos clientes que estão à sua frente. Assim que o próximo atendente estiver livre, ele irá assumir o seu chamado imediatamente.\n\nPedimos a sua compreensão e agradecemos por aguardar!","time":"14/01/2026 06:10:59"},{"role":"client","text":"Ok, combinado","time":"14/01/2026 06:11:23"},{"role":"client","text":"Seja bem-vindo à Cidade Viva. Sou Thayanne Sales","time":"14/01/2026 08:05:38"},{"role":"agent","text":"*Thayanne Sales:* Vou lhe enviar as informações sobre o curso","time":"14/01/2026 08:05:47","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"client","text":"Joia","time":"14/01/2026 08:05:57"},{"role":"agent","text":"*Thayanne Sales:* *Bacharelado em Direito*\n\n*GRADUAÇÃO COM COSMOVISÃO CRISTÃ*\nValorização do Direito clássico, sem viés ideológico, o Direito tratado numa cosmovisão cristã.\n\n*NOTA MÁXIMA NO MEC*\nGraduação com a maior avaliação junto ao MEC, conceito 05 estrelas ( *bit.ly/3LlEgJS* ) com duração de 5 anos. \n\n*PRÁTICA JURÍDICA*\nÚnico curso no Brasil com vivência de prática jurídica do primeiro ao décimo período.\n\n*NÚCLEO*\nPrimeiro e único núcleo de prática jurídica em Lei Geral de Proteção de Dados (LGPD).\n\n*VOCAÇÃO*\nEspecialização durante a graduação com disciplinas optativas nas áreas: \n\na) Serviço Público; \nb) Advocacia Empreendedora; \nc) Academia\n\n*BIBLIOTECA DIGITAL*\nRevista dos Tribunais online e a Biblioteca Digital Proview da Revista dos Tribunais. Kindles com assinatura Unlimited.\n\n*AULAS PRESENCIAIS*\nDe segunda à sexta, das 19h às 22h - goo.gl/maps/tb5occMvgJGHsjwz9.","time":"14/01/2026 08:06:03","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Thayanne Sales:* Segue a matriz curricular do curso de Direito *bit.ly/3SpepqX*","time":"14/01/2026 08:06:08","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Thayanne Sales:* A mensalidade da Graduação em Direito está R$ 1.407,95. \n\n🤩 Estamos com uma condição excepcional, desconto de 60% na pontualidade durante toda graduação que ficará o valor de R$ 563,18.\n\nNão há taxa de matrícula, sendo a primeira mensalidade paga no ato da inscrição, e as demais mensalidades pagas até o dia 10 de cada mês.\n\n🌟 Valor promocional: (Semestralidade R$ 3.379,08).\n⚠️ Valor mensal está sujeito a mudança de acordo a data de matrícula:\n\n Matrículas realizadas até em JANEIRO: 6 mensalidades de R$ 563,18 = R$ 3.379,08\n Matrículas realizadas até em FEVEREIRO: 5 mensalidades de R$ 675,81 = R$ 3.379,08\nMatrículas realizadas até MARÇO: 04 mensalidades R$ 844,77 = R$ 3.3.79,08\n\nInício das aulas em Fevereiro de 2026 📚📖💻","time":"14/01/2026 08:06:15","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Thayanne Sales:* ✅ PROCEDIMENTO DE MATRÍCULA:\n\nRealize a matrícula de acordo com a sua forma de ingresso, basta acessar o link correspondente abaixo:\n\n1 - Aproveitamento do ENEM:\nbit.ly/FICV-Enem\n\n2 - Vestibular Agendado:\nbit.ly/FICV-Vestibular\n\n3 - Seleção de Graduados:\nbit.ly/FICV-Graduados\n\n📝 Após preencher seus dados, o sistema disponibilizará o pagamento da primeira parcela e o contrato para aceite. Não há cobrança de matrícula.😊","time":"14/01/2026 08:06:20","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"client","text":"Atendimento Finalizado!\n\nStephanne carvalho, esperamos que sua solicitação tenha sido totalmente resolvida.\n\nO seu feedback é muito importante para nós, então agradecemos se puder avaliar nosso atendimento em uma pesquisa futura.\n\nA FICV agradece o seu contato. Estamos sempre à disposição!","time":"15/01/2026 08:25:34"},{"role":"client","text":"Sua sessão irá expirar em 2 minutos!","time":"17/01/2026 08:03:58"},{"role":"client","text":"Sua sessão expirou!","time":"17/01/2026 08:05:59"}]$tag$, $tag$2026-01-14 06:10:57+00$tag$, FALSE, FALSE, 5.8, $tag$2026-03-01 16:46:57.607947+00$tag$, 5, 10, 3, 2, 9, 5, $tag$65b591e2-df83-4fd5-9de1-52b0445d3ed1$tag$, $tag$approved$tag$, TRUE, NULL, '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET protocol = EXCLUDED.protocol, contact = EXCLUDED.contact, agent_id = EXCLUDED.agent_id, agent_name = EXCLUDED.agent_name, message_content = EXCLUDED.message_content, timestamp = EXCLUDED.timestamp, has_empathy = EXCLUDED.has_empathy, closing_attempt = EXCLUDED.closing_attempt, final_score = EXCLUDED.final_score, created_at = EXCLUDED.created_at, empathy_score = EXCLUDED.empathy_score, clarity_score = EXCLUDED.clarity_score, depth_score = EXCLUDED.depth_score, commercial_score = EXCLUDED.commercial_score, agility_score = EXCLUDED.agility_score, message_count = EXCLUDED.message_count, upload_id = EXCLUDED.upload_id, status = EXCLUDED.status, is_commercial = EXCLUDED.is_commercial, overall_conclusion = EXCLUDED.overall_conclusion, improvements = EXCLUDED.improvements;
INSERT INTO public.messages_logs (id, protocol, contact, agent_id, agent_name, message_content, timestamp, has_empathy, closing_attempt, final_score, created_at, empathy_score, clarity_score, depth_score, commercial_score, agility_score, message_count, upload_id, status, is_commercial, overall_conclusion, improvements) VALUES ($tag$16ed6463-36b8-4e3b-8c8d-b60062ef7f8a$tag$, $tag$2026011400066$tag$, $tag$Isabel Cristina (5581991230214)$tag$, NULL, $tag$Karina Pimentel$tag$, $tag$[{"role":"client","text":"Oi, vim pelo Instagram e quero mais informações","time":"14/01/2026 11:16:32"},{"role":"client","text":"🌟 Bom dia Isabel Cristina! Que alegria ter você aqui com a gente! 🙌","time":"14/01/2026 11:16:36"},{"role":"client","text":"Seja bem-vindo ao atendimento digital da Cidade Viva","time":"14/01/2026 11:16:40"},{"role":"client","text":"Você poderá tirar dúvidas sobre Igreja, Faculdade, Fundação, Livraria e nosso Sistema de Ensino.\n","time":"14/01/2026 11:16:44"},{"role":"client","text":"🔐 *Em conformidade com a Lei Geral de Proteção de Dados (LGPD), seus dados serão utilizados exclusivamente para fins de atendimento, tratados com segurança e nunca compartilhados com terceiros sem sua autorização.*","time":"14/01/2026 11:16:48"},{"role":"client","text":"Antes de seguirmos, pedimos apenas um minuto para conferir nossos Termos de Uso e Política de Privacidade. Neles, você encontra todos os detalhes sobre como tratamos seus dados em conformidade com a LGPD, seja para assuntos da Igreja, Escola, Fundação ou outras áreas da organização.","time":"14/01/2026 11:16:54"},{"role":"client","text":"Acesse o documento completo aqui: https://drive.google.com/file/d/1k1z1zHcYSVRfRcy8ZH_jridrI2xRP-en/view?usp=sharing \n\n✅ Ao continuar neste atendimento, você declara estar ciente e de acordo com estes termos.","time":"14/01/2026 11:17:00"},{"role":"client","text":"Você concorda com o uso dos seus dados conforme informado acima?","time":"14/01/2026 11:17:01"},{"role":"client","text":"Sim, concordo","time":"14/01/2026 11:19:14"},{"role":"client","text":"✅ Obrigado, Isabel Cristina! Agora que você concordou com os termos da LGPD, podemos continuar seu atendimento. ","time":"14/01/2026 11:19:15"},{"role":"client","text":"Agora, selecione no menu abaixo com qual área da Cidade Viva você deseja falar.","time":"14/01/2026 11:19:20"},{"role":"client","text":"Faculdade \n Faculdade Internacional Cidade Viva","time":"14/01/2026 11:19:37"},{"role":"client","text":"Olá! Isabel Cristina!👋\n É um prazer te receber aqui, na Faculdade Internacional Cidade Viva. 😊","time":"14/01/2026 11:19:38"},{"role":"client","text":"Escolha uma opção abaixo para continuarmos:","time":"14/01/2026 11:19:42"},{"role":"client","text":"Falar com um atendente","time":"14/01/2026 11:19:54"},{"role":"client","text":"Certo! 🙌\n\nEstamos localizando um atendente para falar com você.\n\nEnquanto isso, me diz rapidinho:\n💬 Sobre qual assunto você precisa de ajuda?\n","time":"14/01/2026 11:19:55"},{"role":"client","text":"Seja bem-vindo à Cidade Viva. Sou Karina Pimentel","time":"14/01/2026 11:38:06"},{"role":"client","text":"Olá bom dia","time":"14/01/2026 11:42:09"},{"role":"client","text":"Sobre teologia","time":"14/01/2026 11:42:14"},{"role":"client","text":"Quantos anos?","time":"14/01/2026 11:42:20"},{"role":"client","text":"Qual o valor?","time":"14/01/2026 11:42:25"},{"role":"client","text":"Amo curso é presencial","time":"14/01/2026 11:42:41"},{"role":"agent","text":"*Karina Pimentel:*  A nossa *Graduação em Teologia Presencial* é Bacharelado e reconhecida pelo MEC ( *bit.ly/3LlEgJS* ), com a duração de 3 anos.\n\nNo formato presencial as aulas acontecem de segunda à quinta-feira das 19h00 às 22h00 aqui no Polo João Pessoa, localizado na Rua Luzia Simões Bartoline, 50 - Aeroclube, João Pessoa-PB.\n\nA nossa base filosófica e teológica é fundamentada na cosmovisão cristã, utilizando o método histórico-gramatical para a interpretação das Sagradas Escrituras. Como Faculdade, diferenciamo-nos de um seminário, que geralmente segue um viés denominacional. Contamos com professores de diferentes tradições cristãs, como Presbiteriana, Batista, Adventista e Anglicana, valorizando assim a integridade intelectual. Todos os nossos docentes são especializados nas suas áreas de atuação.","time":"14/01/2026 11:43:16","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Karina Pimentel:* A mensalidade da Graduação Presencial em Teologia fica R$ 549,56.\n\n🤩 Estamos com uma condição especial, *desconto de 10%* na pontualidade durante toda graduação, que fica apenas R$ 494,60.  *Usando o cupom de desconto: BOLSA10*\n\nNão há taxa de matrícula, sendo a primeira mensalidade paga no ato da matrícula, e as demais mensalidades pagas no dia 10 dos meses subsequentes ao início das aulas.\n\n🌟 *Valor promocional:* (Semestralidade R$ 2.967,62).\n\n⚠ *Valor mensal está sujeito a mudança de acordo a data de matrícula:*\n \nMatrículas realizadas até em JANEIRO: 6 mensalidades de R$ 494,60 = R$ 2.967,62\nMatrículas realizadas até em FEVEREIRO: 5 mensalidades de R$ 593,52 = R$ 2.967,62\nMatrículas realizadas até MARÇO: 04 mensalidades R$ 741,90  = R$ 2.967,62\n\n🗓️ Início das aulas: Fevereiro de 2026 📚💻","time":"14/01/2026 11:43:34","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"client","text":"Tem semipresencial","time":"14/01/2026 11:45:56"},{"role":"agent","text":"*Karina Pimentel:* Não. Teremos Ead ou Presencial!","time":"14/01/2026 11:51:48","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"client","text":"Ead","time":"14/01/2026 11:59:23"},{"role":"client","text":"O vlaor","time":"14/01/2026 11:59:26"},{"role":"agent","text":"*Karina Pimentel:*  A nossa *Graduação em Teologia EAD* é Bacharelado reconhecido pelo MEC ( *bit.ly/3LlEgJS* ), com a duração de 3 anos.\n\nNo formato EAD, as aulas são ao vivo e gravadas e ficam à disposição do aluno no Ambiente Virtual de Aprendizagem, para assistir no seu tempo. As aulas ao vivo terão dia e horário definidos previamente e poderão ser assistidas posteriormente, pois ficarão gravadas.\n\nO aluno tem acesso aos materiais disponibilizados por nossos professores, tem encontros remotos com tutores, através da Plataforma Virtual da FICV (Plataforma Moodle), além de contar com materiais de apoio acadêmico-científico.","time":"14/01/2026 13:42:41","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Karina Pimentel:* \n 🎓 Graduação EAD em Teologia por apenas R$ 399,70/mês! 🤩 Aproveite a condição especial: 10% de desconto na pontualidade durante toda a graduação, reduzindo o valor para R$ 359,73 por mês! 🎉 Usando o cupom *BOLSA10*\n\n✨ Sem taxa de matrícula! A primeira mensalidade é paga no ato da inscrição, e a próxima apenas no mês de início das aulas.\n\n💥 Valor promocional: Semestralidade por R$ 2.158,38!\n\n⚠ Atenção: O valor mensal pode variar de acordo com a data de matrícula:\n\nMatrículas realizadas até em JANEIRO: 6 mensalidades de R$ 359,73 = R$ 2.158,38\nMatrículas realizadas até em FEVEREIRO: 5 mensalidades de R$  431,67 = R$2.158,38\nMatrículas realizadas até MARÇO: 04 mensalidades R$ 539,59 = R$ 2.158,38\n\n🗓️ Início das aulas: Fevereiro de 2026 📚💻","time":"14/01/2026 13:43:05","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Karina Pimentel:*  Bom dia! Ficou alguma dúvida? O que está faltando para você dar esse passo e ingressar no curso? Tenho certeza de que será transformador em sua vida. 😊","time":"15/01/2026 11:41:12","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"client","text":"Atendimento Finalizado!\n\nIsabel Cristina, esperamos que sua solicitação tenha sido totalmente resolvida.\n\nO seu feedback é muito importante para nós, então agradecemos se puder avaliar nosso atendimento em uma pesquisa futura.\n\nA FICV agradece o seu contato. Estamos sempre à disposição!","time":"15/01/2026 11:41:15"},{"role":"client","text":"Sua opinião é muito importante para nós.\nPor gentileza, avalie o atendimento realizado, considerando 1 como muito insatisfeito e 5 como muito satisfeito.","time":"15/01/2026 11:41:15"},{"role":"client","text":"Isabel Cristina, Obrigado pelo seu interesse na Cidade Viva.\n\nCaso deseje outra informação, não hesite em entrar em contato com a gente!\n  \nAté mais!","time":"15/01/2026 11:56:16"}]$tag$, $tag$2026-01-14 11:16:32+00$tag$, FALSE, FALSE, 8.2, $tag$2026-03-01 16:46:57.607947+00$tag$, 10, 10, 10, 2, 9, 6, $tag$65b591e2-df83-4fd5-9de1-52b0445d3ed1$tag$, $tag$approved$tag$, TRUE, NULL, '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET protocol = EXCLUDED.protocol, contact = EXCLUDED.contact, agent_id = EXCLUDED.agent_id, agent_name = EXCLUDED.agent_name, message_content = EXCLUDED.message_content, timestamp = EXCLUDED.timestamp, has_empathy = EXCLUDED.has_empathy, closing_attempt = EXCLUDED.closing_attempt, final_score = EXCLUDED.final_score, created_at = EXCLUDED.created_at, empathy_score = EXCLUDED.empathy_score, clarity_score = EXCLUDED.clarity_score, depth_score = EXCLUDED.depth_score, commercial_score = EXCLUDED.commercial_score, agility_score = EXCLUDED.agility_score, message_count = EXCLUDED.message_count, upload_id = EXCLUDED.upload_id, status = EXCLUDED.status, is_commercial = EXCLUDED.is_commercial, overall_conclusion = EXCLUDED.overall_conclusion, improvements = EXCLUDED.improvements;
