INSERT INTO public.messages_logs (id, protocol, contact, agent_id, agent_name, message_content, timestamp, has_empathy, closing_attempt, final_score, created_at, empathy_score, clarity_score, depth_score, commercial_score, agility_score, message_count, upload_id, status, is_commercial, overall_conclusion, improvements) VALUES ($tag$1e52d81a-7aad-4fa8-8589-5c06af77a000$tag$, $tag$2026011400018$tag$, $tag$Albert (85569286002)$tag$, NULL, $tag$Thayanne Sales$tag$, $tag$[{"role":"client","text":"Oi, já preenchi meus dados na página Teologia Novo Testamento e quero mais informações.","time":"14/01/2026 08:54:25"},{"role":"client","text":"🌟 Bom dia Albert! Que alegria ter você aqui com a gente! 🙌","time":"14/01/2026 08:54:26"},{"role":"client","text":"Seja bem-vindo ao atendimento digital da Cidade Viva","time":"14/01/2026 08:54:31"},{"role":"client","text":"Você poderá tirar dúvidas sobre Igreja, Faculdade, Fundação, Livraria e nosso Sistema de Ensino.\n","time":"14/01/2026 08:54:35"},{"role":"client","text":"🔐 *Em conformidade com a Lei Geral de Proteção de Dados (LGPD), seus dados serão utilizados exclusivamente para fins de atendimento, tratados com segurança e nunca compartilhados com terceiros sem sua autorização.*","time":"14/01/2026 08:54:39"},{"role":"client","text":"Antes de seguirmos, pedimos apenas um minuto para conferir nossos Termos de Uso e Política de Privacidade. Neles, você encontra todos os detalhes sobre como tratamos seus dados em conformidade com a LGPD, seja para assuntos da Igreja, Escola, Fundação ou outras áreas da organização.","time":"14/01/2026 08:54:45"},{"role":"client","text":"Acesse o documento completo aqui: https://drive.google.com/file/d/1k1z1zHcYSVRfRcy8ZH_jridrI2xRP-en/view?usp=sharing \n\n✅ Ao continuar neste atendimento, você declara estar ciente e de acordo com estes termos.","time":"14/01/2026 08:54:50"},{"role":"client","text":"Você concorda com o uso dos seus dados conforme informado acima?","time":"14/01/2026 08:54:51"},{"role":"client","text":"Sim, concordo","time":"14/01/2026 08:55:13"},{"role":"client","text":"✅ Obrigado, Albert! Agora que você concordou com os termos da LGPD, podemos continuar seu atendimento. ","time":"14/01/2026 08:55:14"},{"role":"client","text":"Agora, selecione no menu abaixo com qual área da Cidade Viva você deseja falar.","time":"14/01/2026 08:55:18"},{"role":"client","text":"Faculdade \n Faculdade Internacional Cidade Viva","time":"14/01/2026 08:55:42"},{"role":"client","text":"Olá! Albert!👋\n É um prazer te receber aqui, na Faculdade Internacional Cidade Viva. 😊","time":"14/01/2026 08:55:43"},{"role":"client","text":"Escolha uma opção abaixo para continuarmos:","time":"14/01/2026 08:55:47"},{"role":"client","text":"Saber sobre os cursos","time":"14/01/2026 08:56:11"},{"role":"client","text":"Perfeito! Qual modalidade de curso você tem interesse?","time":"14/01/2026 08:56:15"},{"role":"client","text":"Pós-Graduação","time":"14/01/2026 08:56:25"},{"role":"client","text":"Esses são os cursos de *Pós-Graduação* que temos disponíveis no momento:","time":"14/01/2026 08:56:29"},{"role":"client","text":"Novo Testamento","time":"14/01/2026 08:56:56"},{"role":"client","text":"Estude profundamente o contexto, a teologia e a mensagem do Novo Testamento.\n\n 🔠 Com Grego Bíblico, exegese e interpretação textual\n 📚 Ideal para pastores, líderes e estudiosos da Bíblia\n 📅 Comece sua formação teológica ainda este ano\n","time":"14/01/2026 08:56:56"},{"role":"client","text":"Quer receber mais detalhes ou falar com um consultor?","time":"14/01/2026 08:57:00"},{"role":"client","text":"Quero saber mais \n Quero saber mais detalhes.","time":"14/01/2026 08:57:32"},{"role":"client","text":"Certo, em alguns instantes um dos nossos Consultores falará contigo.\nFique à vontade para interagir ou fazer alguma pergunta, OK?","time":"14/01/2026 08:57:33"},{"role":"client","text":"Olá bom dia. \nGostaria de saber se é possível cursar a pós  em teologia bíblica exegese do novo testamento com bacharel livre em teologia?","time":"14/01/2026 08:58:52"},{"role":"client","text":"Seja bem-vindo à Cidade Viva. Sou Thayanne Sales","time":"14/01/2026 09:01:32"},{"role":"agent","text":"*Thayanne Sales:* Bom dia!","time":"14/01/2026 09:01:54","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Thayanne Sales:* Não entendi a parte do bacharel livre?","time":"14/01/2026 09:02:23","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"client","text":"Bom dia, \nCursei teologia por 3 anos e meio no seminário Batista livre de São Paulo. \nMeu certificado é de bacharel livre em teologia","time":"14/01/2026 09:05:20"},{"role":"client","text":"Arquivo de imagem | (https://igrejabatista.widechat.com.br/config/storage/view/6967868d65bb2b37d1041039)","time":"14/01/2026 09:05:33"},{"role":"client","text":"Gostaria de saber se atende os pré requisitos para cursar a pós","time":"14/01/2026 09:06:09"},{"role":"agent","text":"*Thayanne Sales:* Certo","time":"14/01/2026 09:06:10","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"client","text":"?","time":"14/01/2026 09:06:13"},{"role":"agent","text":"*Thayanne Sales:* É possível cursar sim, mas não vai sair como pós-graduação. Vai sair como curso livre","time":"14/01/2026 09:06:44","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"client","text":"Entendi, muito obrigado","time":"14/01/2026 09:07:39"},{"role":"agent","text":"*Thayanne Sales:* Vamos prosseguir com a sua matricula no curso?","time":"14/01/2026 09:10:57","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"client","text":"Uma dúvida, \nComo seria a certificação de curso livre ?","time":"14/01/2026 10:33:57"},{"role":"agent","text":"*Thayanne Sales:* Você recebe o diploma sai lá sai escrito como curso livre ","time":"14/01/2026 10:39:08","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Thayanne Sales:* Olá Bom dia! Tudo bom?\nQue alegria falar com você! 👋🏼\n\nConseguiu fazer a sua matricula?","time":"15/01/2026 08:27:17","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"client","text":"Atendimento Finalizado!\n\nAlbert, esperamos que sua solicitação tenha sido totalmente resolvida.\n\nO seu feedback é muito importante para nós, então agradecemos se puder avaliar nosso atendimento em uma pesquisa futura.\n\nA FICV agradece o seu contato. Estamos sempre à disposição!","time":"15/01/2026 10:43:23"},{"role":"client","text":"Sua opinião é muito importante para nós.\nPor gentileza, avalie o atendimento realizado, considerando 1 como muito insatisfeito e 5 como muito satisfeito.","time":"15/01/2026 10:43:25"},{"role":"client","text":"Albert, Obrigado pelo seu interesse na Cidade Viva.\n\nCaso deseje outra informação, não hesite em entrar em contato com a gente!\n  \nAté mais!","time":"15/01/2026 10:58:26"}]$tag$, $tag$2026-01-14 08:54:25+00$tag$, FALSE, FALSE, 8.2, $tag$2026-03-01 16:46:57.607947+00$tag$, 10, 10, 10, 2, 9, 7, $tag$65b591e2-df83-4fd5-9de1-52b0445d3ed1$tag$, $tag$approved$tag$, TRUE, NULL, '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET protocol = EXCLUDED.protocol, contact = EXCLUDED.contact, agent_id = EXCLUDED.agent_id, agent_name = EXCLUDED.agent_name, message_content = EXCLUDED.message_content, timestamp = EXCLUDED.timestamp, has_empathy = EXCLUDED.has_empathy, closing_attempt = EXCLUDED.closing_attempt, final_score = EXCLUDED.final_score, created_at = EXCLUDED.created_at, empathy_score = EXCLUDED.empathy_score, clarity_score = EXCLUDED.clarity_score, depth_score = EXCLUDED.depth_score, commercial_score = EXCLUDED.commercial_score, agility_score = EXCLUDED.agility_score, message_count = EXCLUDED.message_count, upload_id = EXCLUDED.upload_id, 